import React from 'react';

function Placements() {
  const stats = [
    { value: "26", label: "Architects", color: "bg-red-800" },
    { value: "24.10", label: "IT & Computer Engineers", color: "bg-teal-700" },
    { value: "16", label: "Management Professionals", color: "bg-orange-700" },
    { value: "10", label: "Science & Technocrats", color: "bg-yellow-600" },
    { value: "12", label: "Aviation Engineers", color: "bg-indigo-900" },
    { value: "8", label: "Designers", color: "bg-red-900" },
    { value: "6.5", label: "Pharmacists", color: "bg-pink-700" }
  ];

  const companies = [
    "Accenture", "Academor", "Adobe", "Federal Bank", "Flipkart", "Bosch", 
    "Capgemini", "Bridgestone", "DCB Bank", "ICICI Bank", "Harsha Engineers", 
    "Gateway Group", "Infosys", "Cygnet Infotech", "Cybercom", "Intech", 
    "Kotak Mahindra Bank", "Godrej", "Jindal", "Medkart Pharmacy", "Home First", 
    "Reliance Industries", "Microsoft", "Torrent Power", "Volkswagen", "TCS", 
    "Sophos", "Tata Motors", "Mitsubishi Electric", "Tata Power", "Torrent Pharma", 
    "Coca-Cola", "Zeus Learning", "Yazaki", "Saint-Gobain", "Wonderbotz", 
    "Ratnamani", "Reliance Digital", "Ninjacart", "Meditab", "Tech Mahindra", 
    "Simform", "Forbes", "Siemens", "Torrecid", "Yes Bank", "Silver Touch", 
    "Sleepwell", "Futurense", "Jio", "Cisco", "Adani Gas"
  ];

  return (
    <div className="fade-in pb-24 h-full overflow-y-auto pr-2">
      <header className="mb-10">
        <h1 className="text-4xl md:text-5xl font-bold text-[#6f5c4e] leading-tight mb-4">
          Placements & Stats
        </h1>
        <p className="text-lg text-gray-500">Excellence in career opportunities and industry exposure</p>
      </header>

      {/* Stats Section */}
      <section className="mb-16">
        <h2 className="text-2xl font-bold text-[#6f5c4e] mb-8 border-l-4 border-brand-brown pl-4">Placement Offers (Lakhs per Year)</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-4">
          {stats.map((stat, index) => (
            <div key={index} className={`${stat.color} p-6 rounded-2xl text-white text-center shadow-lg transform hover:scale-105 transition-transform`}>
              <div className="text-3xl font-black mb-1">{stat.value}</div>
              <div className="text-[10px] uppercase font-bold leading-tight opacity-90">{stat.label}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Companies Section */}
      <section className="">
        <h2 className="text-2xl font-bold text-[#6f5c4e] mb-8 border-l-4 border-brand-brown pl-4">Placements in Campus</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
          {companies.map((company, index) => (
            <div 
              key={index} 
              className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center justify-center text-center transition-all hover:shadow-md hover:border-brand-brown/20 group"
            >
              <span className="text-sm font-semibold text-gray-600 group-hover:text-brand-brown tracking-wide uppercase italic">
                {company}
              </span>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}

export default Placements;
